const GAME_DEMOS={mathDash:{score:0,timer:100,interval:null,correctAnswer:0,init(){const t=document.getElementById("web-game-container");t.innerHTML=`
                <div class="web-game math-dash">
                    <div class="game-hud">
                        <span>BALL: <strong id="md-score">0</strong></span>
                        <div class="progress-bar"><div id="md-timer" style="width:100%"></div></div>
                    </div>
                    <div class="question-box" id="md-question">? + ?</div>
                    <div class="options-grid" id="md-options"></div>
                </div>
            `,this.nextQuestion(),this.startTimer()},nextQuestion(){const t=Math.floor(Math.random()*10)+1,i=Math.floor(Math.random()*10)+1;this.correctAnswer=t+i,document.getElementById("md-question").textContent=`${t} + ${i} = ?`;const n=[this.correctAnswer];for(;n.length<4;){const e=this.correctAnswer+(Math.floor(Math.random()*5)+1)*(Math.random()>.5?1:-1);e>0&&!n.includes(e)&&n.push(e)}n.sort(()=>Math.random()-.5);const o=document.getElementById("md-options");o.innerHTML="",n.forEach(e=>{const s=document.createElement("button");s.className="opt-btn",s.textContent=e,s.onclick=()=>this.checkAnswer(e),o.appendChild(s)}),this.timer=100},checkAnswer(t){t===this.correctAnswer?(this.score+=10,document.getElementById("md-score").textContent=this.score,this.nextQuestion()):this.gameOver()},startTimer(){this.interval=setInterval(()=>{this.timer-=1.5;const t=document.getElementById("md-timer");t&&(t.style.width=this.timer+"%"),this.timer<=0&&this.gameOver()},100)},gameOver(){clearInterval(this.interval),alert(`O'yin tugadi! Ball: ${this.score}`),document.getElementById("game-demo-overlay").classList.remove("open")}}};function openGameDemo(t){document.getElementById("game-demo-overlay").classList.add("open"),t==="math"&&GAME_DEMOS.mathDash.init()}window.openGameDemo=openGameDemo;
